# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

def lambda_handler(event, context):
    # Initialize the SNS client
    sns_client = boto3.client('sns')
    
    # Extract message content and topic ARN from the event data
    message_content = event.get('message_content', 'Default Message')
    topic_arn = event.get('topic_arn', '')
    
    if not topic_arn:
        return {
            'statusCode': 400,
            'body': json.dumps('Topic ARN is missing in the event data.')
        }
    
    # Define a function to publish messages
    def publish_message(topic_arn, message_content):
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message_content
        )
        return response
    
    try:
        # Publish the message to the specified SNS topic
        response = publish_message(topic_arn, message_content)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'response': response
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': str(e)
            })
        }